const express = require('express');
const multer = require('multer');
const path = require('path');
const app = express();

// Configure disk storage
const storage = multer.diskStorage({
  destination: (req, file, cb) => {
    cb(null, path.join(__dirname, 'uploads'));
  },
  filename: (req, file, cb) => {
    // Create unique filename: timestamp-originalname
    const uniqueName = `${Date.now()}-${file.originalname}`;
    cb(null, uniqueName);
  }
});

// File filter — only allow images
const fileFilter = (req, file, cb) => {
  const allowedTypes = ['image/jpeg', 'image/png', 'image/gif', 'image/webp'];
  if (allowedTypes.includes(file.mimetype)) {
    cb(null, true);  // Accept file
  } else {
    cb(new Error('Only image files are allowed'), false); // Reject
  }
};

const upload = multer({
  storage,
  fileFilter,
  limits: { fileSize: 5 * 1024 * 1024 } // 5MB max
});

// Single file upload endpoint
app.post('/api/upload/avatar', upload.single('avatar'), (req, res) => {
  if (!req.file) {
    return res.status(400).json({ error: 'No file uploaded' });
  }

  res.json({
    message: 'File uploaded successfully',
    file: {
      filename: req.file.filename,
      originalName: req.file.originalname,
      mimetype: req.file.mimetype,
      size: req.file.size,
      path: req.file.path
    }
  });
});

// Handle multer errors
app.use((err, req, res, next) => {
  if (err instanceof multer.MulterError) {
    if (err.code === 'LIMIT_FILE_SIZE') {
      return res.status(400).json({ error: 'File too large. Max size is 5MB.' });
    }
    return res.status(400).json({ error: err.message });
  }
  if (err.message === 'Only image files are allowed') {
    return res.status(400).json({ error: err.message });
  }
  next(err);
});

app.listen(3000, () => console.log('Upload server on port 3000'));

const express = require('express');
const multer = require('multer');
const app = express();

const upload = multer({
  storage: multer.memoryStorage(), // Store in memory as Buffer
  limits: { fileSize: 10 * 1024 * 1024 } // 10MB per file
});

// Multiple files from the same field
app.post('/api/upload/photos', upload.array('photos', 5), (req, res) => {
  if (!req.files || req.files.length === 0) {
    return res.status(400).json({ error: 'No files uploaded' });
  }

  const fileInfo = req.files.map(file => ({
    originalName: file.originalname,
    mimetype: file.mimetype,
    size: file.size,
    // file.buffer contains the raw file data
    bufferSize: file.buffer.length
  }));

  res.json({
    message: `${req.files.length} files uploaded`,
    files: fileInfo
  });
});

// Multiple fields with different file types
app.post('/api/upload/profile', upload.fields([
  { name: 'avatar', maxCount: 1 },
  { name: 'resume', maxCount: 1 },
  { name: 'portfolio', maxCount: 5 }
]), (req, res) => {
  res.json({
    avatar: req.files['avatar'] ? req.files['avatar'][0].originalname : null,
    resume: req.files['resume'] ? req.files['resume'][0].originalname : null,
    portfolioCount: req.files['portfolio'] ? req.files['portfolio'].length : 0,
    // Text fields from the multipart form
    name: req.body.name,
    bio: req.body.bio
  });
});

app.listen(3000, () => console.log('Server on port 3000'));

